INSERT INTO metadata_vocabularies
  (id, namespace_url, prefix, label, information, inserted_at, updated_at)
VALUES
  (6, 'http://www.vraweb.org/vracore/vracore4#', 'vra', 'VRA Core 4.0', 'Visual Resources Association Core Categories — three-entity model (Work, Image, Collection) for visual art resources. Library of Congress.', NOW(), NOW()),
  (7, 'http://www.getty.edu/CDWA/CDWALite/', 'cdwalite', 'CDWA Lite', 'Categories for the Description of Works of Art (Lite subset) — OAI-PMH XML schema for art objects. Getty Research Institute.', NOW(), NOW()),
  (8, 'http://www.w3.org/2003/12/exif/ns#', 'exif', 'EXIF', 'Exchangeable Image File Format — technical metadata embedded in image files (ISO 12234-2).', NOW(), NOW()),
  (9, 'http://iptc.org/std/Iptc4xmpCore/1.0/xmlns/', 'iptc', 'IPTC Photo Metadata', 'IPTC Core — descriptive and rights metadata for photographic images. International Press Telecommunications Council.', NOW(), NOW()),
  (10, 'http://ns.adobe.com/xap/1.0/', 'xmp', 'XMP', 'Adobe Extensible Metadata Platform — extensible metadata embedded in digital files. Includes xmpRights and xmpMM sub-namespaces.', NOW(), NOW()),
  (11, 'https://schema.org/', 'schema', 'Schema.org', 'Schema.org vocabulary — structured data for web discoverability (JSON-LD / Microdata). Covers CreativeWork, VisualArtwork, Book, ArchiveComponent, Museum, etc.', NOW(), NOW()),
  (12, 'http://www.loc.gov/MARC21/slim#', 'marc21', 'MARC 21', 'Machine-Readable Cataloging — primary library catalogue interchange format. Library of Congress.', NOW(), NOW()),
  (13, 'http://www.loc.gov/mods/v3#', 'mods', 'MODS 3.x', 'Metadata Object Description Schema — XML-based, MARC-derived library metadata. Widely used in institutional repositories. Library of Congress.', NOW(), NOW()),
  (14, 'http://id.loc.gov/ontologies/bibframe/', 'bf', 'BIBFRAME 2.0', 'Bibliographic Framework — RDF/Linked Data replacement for MARC modelling Work → Instance → Item. Library of Congress.', NOW(), NOW()),
  (15, 'http://www.loc.gov/METS/', 'mets', 'METS', 'Metadata Encoding and Transmission Standard — XML container for packaging digital objects with descriptive, administrative and structural metadata. Library of Congress.', NOW(), NOW()),
  (16, 'http://ns.editeur.org/onix/3.0/reference#', 'onix', 'ONIX 3.0', 'Online Information eXchange — book supply-chain metadata standard. EDItEUR. Useful for acquisition and e-resource workflows.', NOW(), NOW()),
  (17, 'http://www.archiveshub.ac.uk/isadg/', 'isadg', 'ISAD(G)', 'General International Standard Archival Description (2nd ed.) — hierarchical description Fonds → Series → File → Item. International Council on Archives.', NOW(), NOW()),
  (18, 'http://ead3.archivists.org/schema/#', 'ead', 'EAD 3', 'Encoded Archival Description — XML finding aid standard implementing ISAD(G). Society of American Archivists / Library of Congress.', NOW(), NOW()),
  (19, 'http://www.archivists.org/ns/eac-cpf#', 'eaccpf', 'EAC-CPF 2.0', 'Encoded Archival Context — Corporate bodies, Persons, Families. Authority records for archival agents. ICA / SAA.', NOW(), NOW()),
  (20, 'https://www.ica.org/standards/RiC/ontology#', 'ric', 'Records in Contexts (RiC)', 'Next-generation archival description standard — OWL Linked Data ontology superseding ISAD(G), ISAAR(CPF), ISDF, ISDIAH. ICA 2023.', NOW(), NOW()),
  (21, 'http://www.loc.gov/premis/rdf/v3/', 'premis', 'PREMIS 3.0', 'PREservation Metadata: Implementation Strategies — standard for digital preservation metadata (objects, events, agents, rights). Library of Congress.', NOW(), NOW()),
  (22, 'http://www.archiveshub.ac.uk/isaar/', 'isaar', 'ISAAR(CPF)', 'International Standard Archival Authority Record for Corporate bodies, Persons, Families (2nd ed.). ICA. Still widely used in AtoM software.', NOW(), NOW()),
  (23, 'http://www.cidoc-crm.org/cidoc-crm/', 'crm', 'CIDOC CRM', 'Conceptual Reference Model for Cultural Heritage Documentation (ISO 21127) — semantic backbone for CH Linked Data. ICOM-CIDOC.', NOW(), NOW()),
  (24, 'http://www.collectionstrust.org.uk/spectrum/', 'spectrum', 'SPECTRUM 5.1', 'UK Museum Collections Management Standard — 21 collection management procedures and object information groups. Collections Trust.', NOW(), NOW()),
  (25, 'http://www.lido-schema.org/schema/v1.0/lido-v1.0#', 'lido', 'LIDO 1.1', 'Lightweight Information Describing Objects — XML interchange format for museum objects used by Europeana and national CH aggregators. ICOM-CIDOC.', NOW(), NOW()),
  (26, 'https://www.object-id.com/vocab/', 'objectid', 'ICOM Object ID', 'Standard for documenting cultural objects to prevent theft and aid recovery. 9 minimum categories. ICOM / Interpol.', NOW(), NOW()),
  (27, 'http://www.europeana.eu/schemas/edm/', 'edm', 'Europeana Data Model (EDM)', 'Europeana Data Model — aggregation model for CH portals, wrapping DC and CIDOC CRM into Linked Data. Europeana Foundation.', NOW(), NOW()),
  (28, 'http://www.w3.org/2004/02/skos/core#', 'skos', 'SKOS', 'Simple Knowledge Organization System — W3C standard for controlled vocabularies, thesauri and classification schemes (AAT, LCSH, TGN).', NOW(), NOW()),
  (29, 'http://iiif.io/api/presentation/3#', 'iiif', 'IIIF Presentation API 3', 'International Image Interoperability Framework Presentation API — Manifest model for image delivery and viewer interoperability across GLAM.', NOW(), NOW());
